7	static buf_t batch_to_bin(ecurve_t curve, const std::vector<bn_t>& x) {
8	  int batch_size = int(x.size());
9	  int curve_size = curve.size();
10	  buf_t bin(batch_size * curve_size);
11	  for (int j = 0; j < batch_size; j++) x[j].to_bin(bin.range(j * curve_size, curve_size));
12	  return bin;
13	}
14	
15	static error_t batch_from_bin(ecurve_t curve, int batch_size, mem_t bin, std::vector<bn_t>& x) {
16	  int curve_size = curve.size();
17	  if (bin.size != batch_size * curve_size) return coinbase::error(E_BADARG);
18	  x.resize(batch_size);
19	  for (int j = 0; j < batch_size; j++) x[j] = bn_t::from_bin(bin.range(j * curve_size, curve_size));
20	  return SUCCESS;
21	}
