23	error_t ec_pve_ac_t::encrypt_row(const pve_base_pke_i& base_pke, const ss::ac_t& ac, const pks_t& ac_pks, mem_t L,
24	                                 ecurve_t curve, mem_t seed, mem_t plain, buf_t& c,
25	                                 std::vector<ciphertext_adapter_t>& quorum_c) const {
26	  error_t rv = UNINITIALIZED_ERROR;
27	  const mod_t& q = curve.order();
28	  crypto::drbg_aes_ctr_t drbg(seed);
29	  bn_t K = drbg.gen_bn(q);
30	
31	  std::map<std::string, bn_t> K_shares = ac.share(curve.order(), K, &drbg);
32	  for (const auto& [path, pub_key_ptr] : ac_pks) {
33	    ciphertext_adapter_t item;
34	    buf_t ct_ser;
35	    if (rv = base_pke.encrypt(pub_key_ptr, L, K_shares[path].to_bin(), drbg.gen(32), ct_ser)) return rv;
36	    item.ct_ser = ct_ser;
37	    quorum_c.push_back(std::move(item));
38	  }
39	
40	  buf_t k_and_iv = crypto::ro::hash_string(K, L).bitlen(256 + iv_bitlen);
41	  mem_t k_aes = k_and_iv.take(32);
42	  mem_t iv = k_and_iv.skip(32);
43	
44	  crypto::aes_gcm_t::encrypt(k_aes, iv, L, tag_size, plain, c);
45	  return SUCCESS;
46	}
