48	error_t ec_pve_ac_t::encrypt_row0(const pve_base_pke_i& base_pke, const ss::ac_t& ac, const pks_t& ac_pks, mem_t L,
49	                                  ecurve_t curve, mem_t r0_1, mem_t r0_2, int batch_size, std::vector<bn_t>& x0,
50	                                  buf_t& c0, std::vector<ciphertext_adapter_t>& quorum_c0) const {
51	  const mod_t& q = curve.order();
52	  x0.resize(batch_size);
53	  crypto::drbg_aes_ctr_t drbg(r0_1);
54	  for (int j = 0; j < batch_size; j++) x0[j] = drbg.gen_bn(q);
55	  return encrypt_row(base_pke, ac, ac_pks, L, curve,
56	                     r0_2,      // seed
57	                     r0_1,      // plain
58	                     c0,        // output
59	                     quorum_c0  // output
60	  );
61	}
