208	error_t ec_pve_ac_t::party_decrypt_row(const pve_base_pke_i& base_pke, const ss::ac_t& ac, int row_index,
209	                                       const std::string& path, pve_keyref_t prv_key, mem_t label,
210	                                       bn_t& out_share) const {
211	  error_t rv = UNINITIALIZED_ERROR;
212	  if (row_index < 0 || row_index >= kappa) return coinbase::error(E_RANGE);
213	  if (Q.empty()) return coinbase::error(E_BADARG);
214	
215	  const row_t& row = rows[row_index];
216	
217	  buf_t L = crypto::sha256_t::hash(label, Q);
218	
219	  std::set<std::string> leaves = ac.list_leaf_names();
220	  std::vector<std::string> sorted_leaves(leaves.begin(), leaves.end());
221	
222	  const ciphertext_adapter_t* c;
223	  if (rv = find_quorum_ciphertext(sorted_leaves, path, row, c)) return rv;
224	
225	  buf_t plain;
226	  if (rv = base_pke.decrypt(prv_key, L, c->ct_ser, plain)) return rv;
227	  out_share = bn_t::from_bin(plain);
228	  return SUCCESS;
229	}
