9	static inline void cb_assert_elgamal_ct_curve(ecurve_t curve) {
10	  // ElGamal operations are used with secret scalars in many protocols (e.g., ZK proving).
11	  // This repo only provides constant-time point addition on some curve backends; for OpenSSL-backed
12	  // curves (P-256/P-384/P-521) point addition is explicitly not constant-time.
13	  //
14	  // Allow bypassing this in explicitly marked variable-time regions (typically verification).
15	  if (!is_vartime_scope()) {
16	    cb_assert(curve.ct_add_support() != ct_add_support_e::None);
17	  }
18	}
19	
20	}  // namespace
21	
22	const mod_t& ec_elgamal_commitment_t::order(ecurve_t curve) { return curve.order(); }
23	
24	std::tuple<ecc_point_t, bn_t> ec_elgamal_commitment_t::local_keygen(ecurve_t curve) {
25	  cb_assert_elgamal_ct_curve(curve);
26	  bn_t k = curve.get_random_value();
27	  ecc_point_t P = curve.mul_to_generator(k);
28	  return std::make_tuple(P, k);
29	}
