31	ec_elgamal_commitment_t ec_elgamal_commitment_t::make_commitment(const ecc_point_t& P, const bn_t& m,
32	                                                                 const bn_t& r)  // m - scalar, P - public key
33	{
34	  ecurve_t curve = P.get_curve();
35	  cb_assert_elgamal_ct_curve(curve);
36	  const auto& G = curve.generator();
37	  const mod_t& q = curve.order();
38	  const bn_t mm = q.mod(m);
39	  const bn_t rr = q.mod(r);
40	  return ec_elgamal_commitment_t(rr * G, curve.mul_add(mm, P, rr));  // m*G + r*P
41	}
42	
43	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator+(const ec_elgamal_commitment_t& E) const {
44	  cb_assert_elgamal_ct_curve(L.get_curve());
45	  crypto::consttime_point_add_scope_t consttime_point_add_scope;
46	  return ec_elgamal_commitment_t(L + E.L, R + E.R);
47	}
48	
49	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator-(const ec_elgamal_commitment_t& E) const {
50	  cb_assert_elgamal_ct_curve(L.get_curve());
51	  crypto::consttime_point_add_scope_t consttime_point_add_scope;
52	  return ec_elgamal_commitment_t(L - E.L, R - E.R);
53	}
54	
55	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator+(const bn_t& s) const {
56	  ecurve_t curve = L.get_curve();
57	  cb_assert_elgamal_ct_curve(curve);
58	  const auto& G = curve.generator();
59	  const bn_t ss = curve.order().mod(s);
60	  crypto::consttime_point_add_scope_t consttime_point_add_scope;
61	  return ec_elgamal_commitment_t(L, R + ss * G);
62	}
63	
64	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator-(const bn_t& s) const {
65	  ecurve_t curve = L.get_curve();
66	  cb_assert_elgamal_ct_curve(curve);
67	  const mod_t& q = order(curve);
68	
69	  bn_t minus_s;
70	  const bn_t ss = q.mod(s);
71	  MODULO(q) minus_s = bn_t(0) - ss;
72	
73	  return *this + minus_s;
74	}
75	
76	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator*(const bn_t& s) const {
77	  cb_assert_elgamal_ct_curve(L.get_curve());
78	  return ec_elgamal_commitment_t(s * L, s * R);
79	}
80	
81	ec_elgamal_commitment_t ec_elgamal_commitment_t::operator/(const bn_t& s) const {
82	  ecurve_t curve = L.get_curve();
83	  cb_assert_elgamal_ct_curve(curve);
84	  const mod_t& q = order(curve);
85	  bn_t s_inv = q.inv(s);
86	  return *this * s_inv;
87	}
88	
89	void ec_elgamal_commitment_t::randomize(const bn_t& r, const ecc_point_t& P) {
90	  ecurve_t curve = L.get_curve();
91	  cb_assert_elgamal_ct_curve(curve);
92	  const auto& G = curve.generator();
93	  const bn_t rr = curve.order().mod(r);
94	  crypto::consttime_point_add_scope_t consttime_point_add_scope;
95	  L += rr * G;
96	  R += rr * P;
97	}
98	
99	void ec_elgamal_commitment_t::randomize(const ecc_point_t& P)  // P is the public key
100	{
101	  ecurve_t curve = L.get_curve();
102	  cb_assert_elgamal_ct_curve(curve);
103	  bn_t r = curve.get_random_value();
104	  randomize(r, P);
105	}
