15	constexpr uint32_t pve_ac_ciphertext_version_v1 = 1;
16	// Defensive limit for untrusted inputs. This bounds allocations/work when ciphertexts come from the network.
17	static constexpr int MAX_BATCH_COUNT = 100000;
18	
19	using coinbase::api::detail::to_internal_curve;
20	
21	struct pve_ac_ciphertext_blob_v1_t {
22	  uint32_t version = pve_ac_ciphertext_version_v1;
23	  uint32_t batch_count = 0;
24	  buf_t ct;  // serialized `coinbase::mpc::ec_pve_ac_t`
25	
26	  void convert(coinbase::converter_t& c) { c.convert(version, batch_count, ct); }
27	};
28	
29	static error_t parse_ac_ciphertext(mem_t ciphertext, pve_ac_ciphertext_blob_v1_t& out_blob) {
30	  error_t rv = coinbase::convert(out_blob, ciphertext);
31	  if (rv) return rv;
32	  if (out_blob.version != pve_ac_ciphertext_version_v1)
33	    return coinbase::error(E_FORMAT, "unsupported ciphertext version");
34	  if (out_blob.batch_count == 0) return coinbase::error(E_FORMAT, "invalid batch count");
35	  if (out_blob.batch_count > static_cast<uint32_t>(MAX_BATCH_COUNT)) return coinbase::error(E_RANGE, "batch too large");
36	  return SUCCESS;
37	}
