54	static error_t validate_leaf_keys_exact(const std::set<std::string>& leaf_names, const leaf_keys_t& keys,
55	                                        const char* what) {
56	  if (leaf_names.empty()) return coinbase::error(E_BADARG, "access_structure: missing leaves");
57	  if (keys.size() != leaf_names.size()) return coinbase::error(E_BADARG, std::string(what) + ": key set mismatch");
58	
59	  for (const auto& [name_view, key] : keys) {
60	    if (name_view.empty()) return coinbase::error(E_BADARG, std::string(what) + ": leaf name must be non-empty");
61	    if (key.size < 0) return coinbase::error(E_BADARG, std::string(what) + ": invalid key size");
62	    if (key.size > 0 && !key.data) return coinbase::error(E_BADARG, std::string(what) + ": missing key bytes");
63	    if (key.size > coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE)
64	      return coinbase::error(E_RANGE, std::string(what) + ": key too large");
65	
66	    if (leaf_names.count(std::string(name_view)) == 0)
67	      return coinbase::error(E_BADARG, std::string(what) + ": unknown leaf name");
68	  }
69	
70	  for (const auto& leaf : leaf_names) {
71	    if (keys.find(std::string_view(leaf)) == keys.end())
72	      return coinbase::error(E_BADARG, std::string(what) + ": missing key for leaf " + leaf);
73	  }
74	
75	  return SUCCESS;
76	}
