106	error_t encrypt_ac(const base_pke_i& base_pke, curve_id curve, const access_structure_t& ac, const leaf_keys_t& ac_pks,
107	                   mem_t label, const std::vector<mem_t>& xs, buf_t& out_ciphertext) {
108	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
109	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg(xs, "xs")) return rv;
110	  error_t rv = UNINITIALIZED_ERROR;
111	
112	  const auto icurve = to_internal_curve(curve);
113	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
114	
115	  if (xs.empty()) return coinbase::error(E_BADARG, "batch_count must be positive");
116	  if (xs.size() > static_cast<size_t>(MAX_BATCH_COUNT)) return coinbase::error(E_RANGE, "batch too large");
117	
118	  // Defensive check: avoid large attacker-controlled allocations when converting `xs[i]` into bignums.
119	  const int max_x_size = icurve.order().get_bin_size();
120	  for (const auto& x : xs) {
121	    if (x.size > max_x_size) return coinbase::error(E_RANGE, "xs element too large", /*to_print_stack_trace=*/false);
122	  }
123	
124	  coinbase::crypto::ss::ac_owned_t ac_internal;
125	  std::set<std::string> leaf_names;
126	  if (rv = to_internal_ac_and_leaves(ac, icurve, ac_internal, leaf_names)) return rv;
127	  if (rv = validate_leaf_keys_exact(leaf_names, ac_pks, "ac_pks")) return rv;
128	
129	  std::vector<coinbase::crypto::bn_t> xs_bn;
130	  xs_bn.reserve(xs.size());
131	  for (const auto& x : xs) xs_bn.push_back(coinbase::crypto::bn_t::from_bin(x));
132	
133	  detail::base_pke_bridge_t bridge(base_pke);
134	
135	  std::map<std::string, coinbase::mem_t> key_mems;
136	  coinbase::mpc::ec_pve_ac_t::pks_t pk_ptrs;
137	  build_internal_leaf_key_ptrs(ac_pks, key_mems, pk_ptrs);
138	
139	  coinbase::mpc::ec_pve_ac_t pve_ct;
140	
141	  out_ciphertext.free();
142	  rv = pve_ct.encrypt(bridge, ac_internal, pk_ptrs, label, icurve, xs_bn);
143	  if (rv) return rv;
144	
145	  pve_ac_ciphertext_blob_v1_t blob;
146	  blob.batch_count = static_cast<uint32_t>(xs.size());
147	  blob.ct = coinbase::convert(pve_ct);
148	
149	  out_ciphertext = coinbase::convert(blob);
150	  return SUCCESS;
151	}
