9	// Access structure used by threshold protocols (e.g., threshold DKG / refresh).
10	//
11	// This is a lightweight view type:
12	// - Leaf party names are represented as `std::string_view` and must outlive the
13	//   protocol call that consumes the access structure.
14	//   (For example, do not construct leaves from temporary `std::string`s.)
15	// - Internal node names are not exposed; the library assigns deterministic,
16	//   unique internal names when converting to the internal representation.
17	//
18	// Notes:
19	// - Leaf names are expected to match the `job_mp_t::party_names` values.
20	// - The root node is unnamed in the internal representation; therefore the root
21	//   of an access structure cannot be a leaf node.
22	struct access_structure_t {
23	  enum class node_type : uint8_t {
24	    leaf = 1,
25	    and_node = 2,
26	    or_node = 3,
27	    threshold = 4,
28	  };
29	
30	  node_type type = node_type::leaf;
31	
32	  // Leaf party name (only meaningful when `type == node_type::leaf`).
33	  std::string_view leaf_name;
34	
35	  // Threshold parameter k (only meaningful when `type == node_type::threshold`).
36	  // Must satisfy: 1 <= k <= children.size().
37	  int32_t threshold_k = 0;
38	
39	  // Child nodes (only meaningful when `type != node_type::leaf`).
40	  std::vector<access_structure_t> children;
41	
42	  static access_structure_t leaf(std::string_view party_name) {
43	    access_structure_t n;
44	    n.type = node_type::leaf;
45	    n.leaf_name = party_name;
46	    return n;
47	  }
48	
49	  static access_structure_t And(std::vector<access_structure_t> ch) {
50	    access_structure_t n;
