93	void node_t::convert_node(coinbase::converter_t& c) {
94	  int temp = int(type);
95	  c.convert(temp);
96	  type = node_e(temp);
97	  c.convert(name, threshold);
98	
99	  uint32_t n = get_n();
100	  c.convert_len(n);
101	
102	  for (int i = 0; i < n; i++) {
103	    node_t* child = c.is_write() ? children[i] : new node_t();
104	    child->convert_node(c);
105	
106	    if (c.is_error()) {
107	      if (!c.is_write()) delete child;
108	      break;
109	    }
110	
111	    if (!c.is_write()) add_child_node(child);
112	  }
113	}
