115	// ac stands for access structure
116	void ac_owned_t::convert(coinbase::converter_t& c)  // static
117	{
118	  bool exists = (root != nullptr);
119	  c.convert(exists);
120	  error_t rv = UNINITIALIZED_ERROR;
121	
122	  if (exists) {
123	    c.convert(curve);
124	    if (!c.is_write() && !curve.valid()) {
125	      rv = coinbase::error(E_FORMAT, "access structure: invalid curve");
126	      c.set_error(rv);
127	      delete root;
128	      root = nullptr;
129	      return;
130	    }
131	    if (!c.is_write()) {
132	      delete root;
133	      root = new node_t();
134	    }
135	
136	    ((node_t*)root)->convert_node(c);
137	    if (c.is_write()) return;
138	
139	    if (!c.is_error()) {
140	      rv = validate_tree();
141	      if (rv == 0) return;
142	    }
143	  } else if (!c.is_write()) {
144	    curve = nullptr;
145	  }
146	
147	  delete root;
148	  root = nullptr;
149	  if (rv) c.set_error(rv);
150	}
