344	error_t ac_t::verify_share_against_ancestors_pub_data(const ecc_point_t& Q, const bn_t& si,
345	                                                      const ac_internal_pub_shares_t& pub_data,
346	                                                      const pname_t& leaf) const {
347	  if (!curve.valid()) return coinbase::error(E_BADARG, "missing curve");
348	  if (Q.get_curve() != curve) return coinbase::error(E_BADARG, "curve mismatch");
349	  auto node = find(leaf);
350	  if (node == nullptr || node->type != node_e::LEAF) return coinbase::error(E_NOT_FOUND);
351	
352	  ecc_point_t expected_pub_share = si * curve.generator();
353	  vartime_scope_t vartime_scope;
354	  const node_t* child = nullptr;
355	
356	  while (node != nullptr) {
357	    auto sorted_children = node->get_sorted_children();
358	
359	    auto it = pub_data.find(node->name);
360	    if (it == pub_data.end()) return coinbase::error(E_BADARG, "missing pub_data key");
361	    ecc_point_t my_pub_share = it->second;
362	
363	    if (node->type == node_e::LEAF || node->type == node_e::OR) {
364	      if (my_pub_share != expected_pub_share) {
365	        return coinbase::error(E_CRYPTO);
366	      }
367	    } else if (node->type == node_e::AND) {
368	      ecc_point_t expected_sum = curve.infinity();
369	      for (size_t i = 0; i < sorted_children.size(); i++) {
370	        auto child_it = pub_data.find(sorted_children[i]->name);
371	        if (child_it == pub_data.end()) return coinbase::error(E_BADARG, "missing pub_data key");
372	        expected_sum += child_it->second;
373	      }
374	      if (expected_sum != my_pub_share) return coinbase::error(E_CRYPTO);
375	    } else if (node->type == node_e::THRESHOLD) {
376	      std::vector<ecc_point_t> quorum(node->threshold);
377	      std::vector<bn_t> quorum_pids(node->threshold);
378	      for (int i = 0; i < node->threshold; i++) {
379	        auto child_it = pub_data.find(sorted_children[i]->name);
380	        if (child_it == pub_data.end()) return coinbase::error(E_BADARG, "missing pub_data key");
381	        quorum[i] = child_it->second;
382	        quorum_pids[i] = sorted_children[i]->get_pid();
383	      }
384	
385	      // NOTE: this is a less efficient implementation. More optimized implementation should store coefficients in the
386	      //       node and run `horner_poly` for each child. At the moment, the code is reconstructing the polynomial from
387	      //       scratch for itself and each of its children.
388	      if (my_pub_share != lagrange_interpolate_exponent(0, quorum, quorum_pids)) return coinbase::error(E_CRYPTO);
389	
390	      for (size_t i = node->threshold; i < sorted_children.size(); i++) {
391	        auto child_it = pub_data.find(sorted_children[i]->name);
392	        if (child_it == pub_data.end()) return coinbase::error(E_BADARG, "missing pub_data key");
393	        if (child_it->second != lagrange_interpolate_exponent(sorted_children[i]->get_pid(), quorum, quorum_pids))
394	          return coinbase::error(E_CRYPTO);
395	      }
396	    } else {
397	      return coinbase::error(E_BADARG);
398	    }
399	
400	    expected_pub_share = my_pub_share;
401	    child = node;
402	    node = node->parent;
403	  }
404	
405	  if (Q != expected_pub_share) return coinbase::error(E_CRYPTO);
406	
407	  return SUCCESS;
408	}
