410	static error_t reconstruct_recursive(const mod_t& q, const node_t* node, const ac_shares_t& shares, bn_t& x) {
411	  error_t rv = UNINITIALIZED_ERROR;
412	  int n = node->get_n();
413	
414	  switch (node->type) {
415	    case node_e::LEAF: {
416	      const auto& [found, share] = lookup(shares, node->name);
417	      if (!found) {
418	        // Missing leaf shares are expected in threshold/OR reconstructions.
419	        // Do not emit stack traces / dylog output for this control-flow condition.
420	        dylog_disable_scope_t dylog_disable_scope;
421	        return coinbase::error(E_INSUFFICIENT);
422	      }
423	      x = *share;
424	    } break;
425	    case node_e::OR:
426	      for (int i = 0; i < n; i++) {
427	        rv = reconstruct_recursive(q, node->children[i], shares, x);
428	        if (rv == SUCCESS) break;
429	        if (rv != E_INSUFFICIENT) return rv;
430	      }
431	      if (rv != SUCCESS) return coinbase::error(E_INSUFFICIENT);
432	      break;
433	    case node_e::AND:
434	      x = 0;
435	      for (int i = 0; i < n; i++) {
436	        bn_t share;
437	        if (rv = reconstruct_recursive(q, node->children[i], shares, share)) return rv;
438	        MODULO(q) x += share;
439	      }
440	      break;
441	
442	    case node_e::THRESHOLD: {
443	      std::vector<bn_t> pids(node->threshold);
444	      std::vector<bn_t> node_shares(node->threshold);
445	      int count = 0;
446	
447	      for (int i = 0; i < n; i++) {
448	        bn_t share;
449	        rv = reconstruct_recursive(q, node->children[i], shares, share);
450	        if (rv == E_INSUFFICIENT) {
451	          rv = SUCCESS;
452	          continue;
453	        }
454	        if (rv) return rv;
455	
456	        pids[count] = node->children[i]->get_pid();
457	        node_shares[count] = share;
458	        count++;
459	        if (count == node->threshold) break;
460	      }
461	
462	      if (count < node->threshold) {
463	        dylog_disable_scope_t dylog_disable_scope;
464	        return coinbase::error(E_INSUFFICIENT);
465	      }
466	
467	      x = lagrange_interpolate(0, node_shares, pids, q);
468	    } break;
469	
470	    case node_e::NONE: {
471	      return coinbase::error(E_CRYPTO);
472	    } break;
473	  }
474	
475	  return SUCCESS;
476	}
