482	static error_t reconstruct_exponent_recursive(const node_t* node, const ac_pub_shares_t& shares, ecc_point_t& P) {
483	  error_t rv = UNINITIALIZED_ERROR;
484	  int n = node->get_n();
485	  const pname_t& name = node->name;
486	
487	  switch (node->type) {
488	    case node_e::LEAF: {
489	      const auto& [found, share] = lookup(shares, name);
490	      if (!found) {
491	        dylog_disable_scope_t dylog_disable_scope;
492	        return coinbase::error(E_INSUFFICIENT, "missing share for leaf node " + name);
493	      }
494	      P = *share;
495	    } break;
496	
497	    case node_e::OR:
498	      for (int i = 0; i < n; i++) {
499	        rv = reconstruct_exponent_recursive(node->children[i], shares, P);
500	        if (rv == SUCCESS) break;
501	        if (rv != E_INSUFFICIENT) return coinbase::error(rv, "cannot reconstruct OR node " + name);
502	      }
503	      if (rv != SUCCESS) return coinbase::error(E_INSUFFICIENT);
504	      break;
505	
506	    case node_e::AND:
507	      for (int i = 0; i < n; i++) {
508	        ecc_point_t Pi;
509	        if (rv = reconstruct_exponent_recursive(node->children[i], shares, Pi))
510	          return coinbase::error(rv, "cannot reconstruct AND node " + name);
511	        if (i == 0)
512	          P = Pi;
513	        else
514	          P = P + Pi;
515	      }
516	      break;
517	
518	    case node_e::THRESHOLD: {
519	      std::vector<bn_t> pids(node->threshold);
520	      std::vector<ecc_point_t> node_shares(node->threshold);
521	      int count = 0;
522	
523	      for (int i = 0; i < n; i++) {
524	        ecc_point_t Pi;
525	        rv = reconstruct_exponent_recursive(node->children[i], shares, Pi);
526	        if (rv == E_INSUFFICIENT) {
527	          rv = SUCCESS;
528	          continue;
529	        }
530	        if (rv) return coinbase::error(rv, "cannot reconstruct threshold node " + name);
531	
532	        pids[count] = node->children[i]->get_pid();
533	        node_shares[count] = Pi;
534	        count++;
535	        if (count == node->threshold) break;
536	      }
537	
538	      if (count < node->threshold) {
539	        dylog_disable_scope_t dylog_disable_scope;
540	        return coinbase::error(E_INSUFFICIENT, "missing share for threshold node " + name);
541	      }
542	
543	      P = lagrange_interpolate_exponent(0, node_shares, pids);
544	    } break;
545	
546	    case node_e::NONE: {
547	      return coinbase::error(E_CRYPTO);
548	    } break;
549	  }
550	
551	  return SUCCESS;
552	}
553	
554	error_t ac_t::reconstruct_exponent(const ac_pub_shares_t& shares, ecc_point_t& P) const {
555	  if (!root) return coinbase::error(E_BADARG, "missing root");
556	  if (!curve.valid()) return coinbase::error(E_BADARG, "missing curve");
557	  allow_ecc_infinity_t allow_ecc_infinity;
558	  for (const auto& [name, share] : shares) {
559	    error_t rv = curve.check(share);
560	    if (rv) return coinbase::error(rv, "invalid share point for " + name);
561	  }
562	
563	  return reconstruct_exponent_recursive(root, shares, P);
564	}
