566	static void list_pub_data_nodes_recursive(const node_t* node, std::set<const node_t*>& node_set) {
567	  if (node->type == node_e::LEAF) {
568	    return;
569	  }
570	  for (const node_t* child : node->children) {
571	    list_pub_data_nodes_recursive(child, node_set);
572	  }
573	  if (node->type == node_e::AND || node->type == node_e::THRESHOLD) {
574	    node_set.insert(node);
575	  }
576	}
