19	inline constexpr size_t MAX_ACCESS_STRUCTURE_DEPTH = 128;
20	inline constexpr size_t MAX_ACCESS_STRUCTURE_NODES = 4096;
21	
22	inline error_t validate_access_structure_node_impl(const access_structure_t& n, size_t depth, size_t& nodes_seen) {
23	  if (++nodes_seen > MAX_ACCESS_STRUCTURE_NODES) return coinbase::error(E_RANGE, "access_structure: too many nodes");
24	  if (depth > MAX_ACCESS_STRUCTURE_DEPTH) return coinbase::error(E_RANGE, "access_structure: too deep");
25	
26	  switch (n.type) {
27	    case access_structure_t::node_type::leaf:
28	      if (n.leaf_name.empty()) return coinbase::error(E_BADARG, "access_structure: leaf name must be non-empty");
29	      if (!n.children.empty()) return coinbase::error(E_BADARG, "access_structure: leaf node must not have children");
30	      if (n.threshold_k != 0) return coinbase::error(E_BADARG, "access_structure: leaf node must not set threshold_k");
31	      return SUCCESS;
32	
33	    case access_structure_t::node_type::and_node:
34	    case access_structure_t::node_type::or_node:
35	      if (n.children.empty()) return coinbase::error(E_BADARG, "access_structure: AND/OR node must have children");
36	      if (!n.leaf_name.empty())
37	        return coinbase::error(E_BADARG, "access_structure: internal node must not set leaf_name");
38	      if (n.threshold_k != 0)
39	        return coinbase::error(E_BADARG, "access_structure: AND/OR node must not set threshold_k");
40	      break;
41	
42	    case access_structure_t::node_type::threshold:
43	      if (n.children.empty()) return coinbase::error(E_BADARG, "access_structure: THRESHOLD node must have children");
44	      if (!n.leaf_name.empty())
45	        return coinbase::error(E_BADARG, "access_structure: internal node must not set leaf_name");
46	      if (n.threshold_k < 1) return coinbase::error(E_BADARG, "access_structure: invalid threshold_k");
47	      if (static_cast<size_t>(n.threshold_k) > n.children.size())
48	        return coinbase::error(E_BADARG, "access_structure: threshold_k > children.size()");
49	      break;
50	    default:
51	      return coinbase::error(E_BADARG, "invalid node type");
52	  }
53	
54	  for (const auto& ch : n.children) {
55	    const error_t rv = validate_access_structure_node_impl(ch, depth + 1, nodes_seen);
56	    if (rv) return rv;
57	  }
58	  return SUCCESS;
59	}
60	
61	inline error_t validate_access_structure_node(const access_structure_t& n) {
62	  size_t nodes_seen = 0;
63	  return validate_access_structure_node_impl(n, /*depth=*/0, nodes_seen);
64	}
65	
66	inline error_t collect_leaf_names(const access_structure_t& n, std::set<std::string>& out) {
67	  struct frame_t {
68	    const access_structure_t* node = nullptr;
69	    size_t depth = 0;
70	  };
71	
72	  size_t nodes_seen = 0;
73	  std::vector<frame_t> stack;
74	  stack.reserve(64);
75	  stack.push_back(frame_t{&n, 0});
76	
77	  while (!stack.empty()) {
78	    const frame_t frame = stack.back();
79	    stack.pop_back();
80	
81	    if (!frame.node) return coinbase::error(E_BADARG, "access_structure: invalid node");
82	    if (++nodes_seen > MAX_ACCESS_STRUCTURE_NODES) return coinbase::error(E_RANGE, "access_structure: too many nodes");
83	    if (frame.depth > MAX_ACCESS_STRUCTURE_DEPTH) return coinbase::error(E_RANGE, "access_structure: too deep");
84	
85	    if (frame.node->type == access_structure_t::node_type::leaf) {
86	      out.insert(std::string(frame.node->leaf_name));
87	      continue;
88	    }
89	
90	    for (const auto& ch : frame.node->children) {
91	      stack.push_back(frame_t{&ch, frame.depth + 1});
92	    }
93	  }
94	
95	  return SUCCESS;
96	}
