98	inline std::string gen_internal_node_name(std::unordered_set<std::string>& used, uint64_t& counter) {
99	  // Generate deterministic unique names that do not collide with leaf names.
100	  while (true) {
101	    counter++;
102	    std::string name = "__cbmpc_ac_node_" + std::to_string(counter);
103	    if (used.insert(name).second) return name;
104	  }
105	}
