107	inline error_t build_internal_ac_node(const access_structure_t& in, size_t depth, bool is_root,
108	                                      std::unordered_set<std::string>& used_names, uint64_t& name_counter,
109	                                      coinbase::crypto::ss::node_t*& out) {
110	  out = nullptr;
111	  if (depth > MAX_ACCESS_STRUCTURE_DEPTH) return coinbase::error(E_RANGE, "access_structure: too deep");
112	
113	  using coinbase::crypto::ss::node_e;
114	  using coinbase::crypto::ss::node_t;
115	
116	  switch (in.type) {
117	    case access_structure_t::node_type::leaf: {
118	      // Leaves must be named. (Root leaf is not supported; root is unnamed.)
119	      if (is_root) return coinbase::error(E_BADARG, "access_structure: root cannot be a leaf node");
120	      auto* node = new node_t(node_e::LEAF, std::string(in.leaf_name));
121	      out = node;
122	      return SUCCESS;
123	    }
124	
125	    case access_structure_t::node_type::and_node:
126	    case access_structure_t::node_type::or_node:
127	    case access_structure_t::node_type::threshold: {
128	      if (in.children.empty()) return coinbase::error(E_BADARG, "access_structure: internal node missing children");
129	
130	      const node_e t = (in.type == access_structure_t::node_type::and_node)  ? node_e::AND
131	                       : (in.type == access_structure_t::node_type::or_node) ? node_e::OR
132	                                                                             : node_e::THRESHOLD;
133	
134	      const int k = (in.type == access_structure_t::node_type::threshold) ? in.threshold_k : 0;
135	
136	      const std::string node_name = is_root ? std::string() : gen_internal_node_name(used_names, name_counter);
137	      auto* node = new node_t(t, node_name, k);
138	
139	      for (const auto& ch : in.children) {
140	        node_t* child = nullptr;
141	        const error_t rv = build_internal_ac_node(ch, depth + 1, /*is_root=*/false, used_names, name_counter, child);
142	        if (rv) {
143	          delete node;  // deletes any already-added children
144	          return rv;
145	        }
146	        node->add_child_node(child);
147	      }
148	
149	      out = node;
150	      return SUCCESS;
151	    }
152	  }
153	
154	  return coinbase::error(E_BADARG, "access_structure: invalid node type");
155	}
156	
157	inline error_t to_internal_access_structure(const access_structure_t& in,
158	                                            const std::vector<std::string_view>& party_names,
159	                                            coinbase::crypto::ecurve_t curve, coinbase::crypto::ss::ac_owned_t& out) {
160	  // Clear any existing tree.
161	  delete out.root;
162	  out.root = nullptr;
163	
164	  if (!curve.valid()) return coinbase::error(E_BADARG, "access_structure: invalid curve");
165	
166	  // Basic shape validation (independent of job).
167	  error_t rv = validate_access_structure_node(in);
168	  if (rv) return rv;
169	  if (in.type == access_structure_t::node_type::leaf)
170	    return coinbase::error(E_BADARG, "access_structure: root cannot be leaf");
171	
172	  // Validate that leaf set matches job.party_names exactly.
173	  std::set<std::string> leaf_names;
174	  rv = collect_leaf_names(in, leaf_names);
175	  if (rv) return rv;
176	
177	  std::set<std::string> party_set;
178	  for (const auto& name_view : party_names) party_set.insert(std::string(name_view));
179	
180	  if (leaf_names != party_set)
181	    return coinbase::error(E_BADARG, "access_structure: leaf names must match job.party_names exactly");
182	
183	  // Build internal node tree with generated internal node names.
184	  std::unordered_set<std::string> used;
185	  used.reserve(leaf_names.size() * 2 + 8);
186	  used.insert(std::string());  // root name
187	  for (const auto& name : leaf_names) used.insert(name);
188	
189	  uint64_t counter = 0;
190	  coinbase::crypto::ss::node_t* root = nullptr;
191	  rv = build_internal_ac_node(in, /*depth=*/0, /*is_root=*/true, used, counter, root);
192	  if (rv) return rv;
193	
194	  out.curve = curve;
195	  out.root = root;
196	
197	  rv = out.validate_tree();
198	  if (rv) {
199	    delete out.root;
200	    out.root = nullptr;
201	    return rv;
202	  }
203	
204	  return SUCCESS;
205	}
