207	inline error_t to_internal_party_set(const std::vector<std::string_view>& party_names,
208	                                     const std::vector<std::string_view>& quorum_party_names,
209	                                     coinbase::mpc::party_set_t& out) {
210	  out = coinbase::mpc::party_set_t::empty();
211	  if (quorum_party_names.empty()) return coinbase::error(E_BADARG, "quorum_party_names must be non-empty");
212	
213	  std::unordered_map<std::string_view, int32_t> index_by_name;
214	  index_by_name.reserve(party_names.size());
215	  for (size_t i = 0; i < party_names.size(); i++) index_by_name.emplace(party_names[i], static_cast<int32_t>(i));
216	
217	  std::unordered_set<std::string_view> seen;
218	  seen.reserve(quorum_party_names.size());
219	  for (const auto& qn : quorum_party_names) {
220	    if (!seen.insert(qn).second) return coinbase::error(E_BADARG, "duplicate quorum party name");
221	    const auto it = index_by_name.find(qn);
222	    if (it == index_by_name.end()) return coinbase::error(E_BADARG, "unknown quorum party name");
223	    out.add(it->second);
224	  }
225	
226	  return SUCCESS;
227	}
